var createError = require('http-errors');
var express = require('express');
var path = require('path');
var cookieParser = require('cookie-parser');
var logger = require('morgan');

var indexRouter = require('./routes/index');
var usersRouter = require('./routes/users');
var apiRouter   = require('./routes/api');

var app = express();

app.set('views', path.join(__dirname, 'views'));
app.set('view engine', 'jade');

app.use(logger('dev'));
app.use(express.json());
app.use(express.urlencoded({ extended: false }));
app.use(cookieParser());
app.use(express.static(path.join(__dirname, 'public')));

app.use('/',      indexRouter);
app.use('/users', usersRouter);
app.use('/api',   apiRouter);

app.use(function (req, res, next) {
  next(createError(404, 'Route not found: ' + req.method + ' ' + req.originalUrl));
});

// Only leak the stack in development.
app.use(function (err, req, res, next) {
  res.locals.message = err.message;
  res.locals.error = req.app.get('env') === 'development' ? err : {};

  res.status(err.status || 500);
  if (req.accepts('html')) {
    res.render('error');
  } else {
    res.json({ error: err.message, status: err.status || 500 });
  }
});

module.exports = app;

#!/usr/bin/env node

/**
 * Module dependencies.
 */

var app = require('../app');
var debug = require('debug')('tpl-express-pro:server');
var http = require('http');

/**
 * Get port from environment and store in Express.
 */

var port = normalizePort(process.env.PORT || '9960');
app.set('port', port);

/**
 * Create HTTP server.
 */

var server = http.createServer(app);

/**
 * Listen on provided port, on all network interfaces.
 */

server.listen(port);
server.on('error', onError);
server.on('listening', onListening);

/**
 * Normalize a port into a number, string, or false.
 */

function normalizePort(val) {
  var port = parseInt(val, 10);

  if (isNaN(port)) {
    // named pipe
    return val;
  }

  if (port >= 0) {
    // port number
    return port;
  }

  return false;
}

/**
 * Event listener for HTTP server "error" event.
 */

function onError(error) {
  if (error.syscall !== 'listen') {
    throw error;
  }

  var bind = typeof port === 'string'
    ? 'Pipe ' + port
    : 'Port ' + port;

  // handle specific listen errors with friendly messages
  switch (error.code) {
    case 'EACCES':
      console.error(bind + ' requires elevated privileges');
      process.exit(1);
      break;
    case 'EADDRINUSE':
      console.error(bind + ' is already in use');
      process.exit(1);
      break;
    default:
      throw error;
  }
}

/**
 * Event listener for HTTP server "listening" event.
 */

function onListening() {
  var addr = server.address();
  var bind = typeof addr === 'string'
    ? 'pipe ' + addr
    : 'port ' + addr.port;
  debug('Listening on ' + bind);
}

(function () {
  'use strict';

  const uptimeEl = document.querySelector('[data-live="uptime"]');
  if (uptimeEl) {
    const initial = parseFloat(uptimeEl.textContent) || 0;
    const start = Date.now() - initial * 1000;
    setInterval(() => {
      const s = (Date.now() - start) / 1000;
      uptimeEl.textContent = formatUptime(s);
    }, 1000);
  }

  function formatUptime(s) {
    if (s < 60)    return s.toFixed(0) + 's';
    if (s < 3600)  return Math.floor(s / 60) + 'm ' + Math.floor(s % 60) + 's';
    return Math.floor(s / 3600) + 'h ' + Math.floor((s % 3600) / 60) + 'm';
  }

  const input  = document.getElementById('echo-input');
  const output = document.getElementById('echo-output');
  const button = document.getElementById('echo-send');

  if (!input || !output || !button) return;

  function setOutput(text, state) {
    output.textContent = text;
    output.className = state || '';
  }

  button.addEventListener('click', async function () {
    let payload;
    try {
      payload = JSON.parse(input.value);
    } catch (err) {
      setOutput('JSON parse error: ' + err.message, 'error');
      return;
    }
    setOutput('POSTing /api/echo…', 'busy');
    button.disabled = true;
    try {
      const t0 = performance.now();
      const res = await fetch('/api/echo', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const json = await res.json();
      const ms = Math.round(performance.now() - t0);
      const header = `HTTP ${res.status} · ${ms} ms\n\n`;
      setOutput(header + JSON.stringify(json, null, 2), res.ok ? 'ok' : 'error');
    } catch (err) {
      setOutput('Network error: ' + err.message, 'error');
    } finally {
      button.disabled = false;
    }
  });
})();

:root {
  --bg: #0a1018;
  --bg-elev: #121a26;
  --bg-card: rgba(18, 26, 38, 0.78);
  --border: rgba(104, 169, 119, 0.18);
  --border-strong: rgba(104, 169, 119, 0.42);
  --text: #e8f0f2;
  --muted: #8a9ba5;
  --node: #68a977;
  --node-deep: #3c6b48;
  --accent: #61dafb;
  --success: #4ade80;
  --warn: #fbbf24;
  --danger: #f87171;
  --code-bg: rgba(2, 8, 14, 0.85);
  --shadow: 0 30px 60px -20px rgba(0, 0, 0, 0.6);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI',
    Roboto, sans-serif;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  min-height: 100%;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
}

body {
  overflow-x: hidden;
  background:
    radial-gradient(900px 500px at 100% 0%, rgba(104, 169, 119, 0.18), transparent 60%),
    radial-gradient(800px 500px at 0% 100%, rgba(97, 218, 251, 0.1), transparent 60%),
    var(--bg);
}

.bg-grid {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background-image:
    linear-gradient(rgba(104, 169, 119, 0.08) 1px, transparent 1px),
    linear-gradient(90deg, rgba(104, 169, 119, 0.08) 1px, transparent 1px);
  background-size: 48px 48px;
  mask-image: radial-gradient(ellipse at center, black 30%, transparent 80%);
  -webkit-mask-image: radial-gradient(ellipse at center, black 30%, transparent 80%);
  opacity: 0.55;
}

#app {
  position: relative;
  z-index: 1;
  max-width: 1100px;
  margin: 0 auto;
  padding: 56px 24px 80px;
}

a { color: var(--accent); text-decoration: none; }
a:hover { text-decoration: underline; }

.hero {
  text-align: center;
  margin-bottom: 48px;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 14px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: rgba(18, 26, 38, 0.7);
  backdrop-filter: blur(8px);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 24px;
}

.badge.badge-error { color: var(--danger); }

.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--success);
  box-shadow: 0 0 12px var(--success);
  animation: pulse 1.6s ease-in-out infinite;
}

.dot-small { width: 6px; height: 6px; }
.dot-error { background: var(--danger); box-shadow: 0 0 12px var(--danger); }

@keyframes pulse {
  0%, 100% { opacity: 0.6; transform: scale(0.9); }
  50%      { opacity: 1;   transform: scale(1.15); }
}

h1 {
  font-size: clamp(2rem, 5vw, 3.4rem);
  line-height: 1.1;
  font-weight: 800;
  margin: 0 0 18px;
  letter-spacing: -0.02em;
  color: var(--text);
}

.gradient-text {
  background: linear-gradient(120deg, var(--node) 0%, var(--accent) 100%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

.gradient-text-error {
  background: linear-gradient(120deg, var(--danger) 0%, var(--warn) 100%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

.lede {
  max-width: 660px;
  margin: 0 auto 28px;
  color: var(--muted);
  font-size: 17px;
  line-height: 1.6;
}

.lede code, .card p code {
  background: var(--code-bg);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--node);
  font-size: 13px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.hero-actions {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 11px 18px;
  border-radius: 10px;
  border: 1px solid transparent;
  font: inherit;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  text-decoration: none;
  color: var(--text);
  background: rgba(255, 255, 255, 0.05);
}

.btn:hover { transform: translateY(-1px); text-decoration: none; }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary {
  background: linear-gradient(120deg, var(--node-deep), var(--node));
  color: #0a1018;
  box-shadow: 0 12px 30px -10px rgba(104, 169, 119, 0.6);
}

.btn-ghost {
  background: transparent;
  border-color: var(--border-strong);
  color: var(--text);
}

.btn-ghost:hover { background: rgba(255, 255, 255, 0.04); }
.btn-small { padding: 8px 14px; font-size: 13px; }

/* Status card */
.console-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px 24px;
  margin-bottom: 40px;
  box-shadow: var(--shadow);
  backdrop-filter: blur(12px);
}

.console-card header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}

.console-card h3 {
  margin: 0;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--muted);
}

.metrics {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 14px;
}

.metric {
  background: rgba(2, 8, 14, 0.5);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 12px 14px;
}

.metric-label {
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 6px;
}

.metric-value {
  font-size: 17px;
  font-weight: 700;
  color: var(--node);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-variant-numeric: tabular-nums;
}

/* Sections */
.section-title {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--muted);
  margin: 0 0 16px;
  display: flex;
  align-items: center;
  gap: 12px;
}

.section-title::before, .section-title::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--border);
}

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(310px, 1fr));
  gap: 18px;
  margin-bottom: 40px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 20px;
  backdrop-filter: blur(12px);
  display: flex;
  flex-direction: column;
  gap: 12px;
  transition: transform 0.2s ease, border-color 0.2s ease;
}

.card:hover {
  transform: translateY(-2px);
  border-color: var(--border-strong);
}

.card header { display: flex; flex-direction: column; gap: 8px; }

.tag {
  align-self: flex-start;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(104, 169, 119, 0.15);
  color: var(--node);
}

.card h2 { font-size: 15px; margin: 0; font-weight: 700; }
.card p {
  margin: 0;
  color: var(--muted);
  font-size: 13.5px;
  line-height: 1.55;
}

.code {
  margin: 0;
  padding: 12px 14px;
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 8px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12px;
  line-height: 1.55;
  color: #d8e3d5;
  overflow-x: auto;
}

.code code { display: block; white-space: pre; }

/* Live request panel */
.live-request {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px 24px;
  margin-bottom: 32px;
  box-shadow: var(--shadow);
  backdrop-filter: blur(12px);
}

.live-request header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  margin-bottom: 16px;
  flex-wrap: wrap;
  gap: 8px;
}

.live-request h3 {
  margin: 0;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--text);
}

.live-request .muted { color: var(--muted); font-size: 13px; }

.live-body {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
  align-items: stretch;
  margin-bottom: 14px;
}

.live-body label {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.live-body label span {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--muted);
}

#echo-input, #echo-output {
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 12px 14px;
  color: var(--text);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
  line-height: 1.55;
  min-height: 120px;
  width: 100%;
  resize: vertical;
  outline: none;
  margin: 0;
  white-space: pre-wrap;
  word-break: break-word;
}

#echo-input:focus { border-color: var(--node); }
#echo-output.error { color: var(--danger); }
#echo-output.busy  { color: var(--warn); }
#echo-output.ok    { color: var(--node); }

#echo-send { margin-bottom: 6px; }

.live-meta {
  font-size: 12.5px;
  color: var(--muted);
  line-height: 1.6;
}

.live-meta code {
  background: var(--code-bg);
  padding: 2px 8px;
  border-radius: 4px;
  color: var(--accent);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 11.5px;
  display: inline-block;
  margin-top: 6px;
  word-break: break-all;
}

.foot {
  text-align: center;
  margin-top: 36px;
  color: var(--muted);
  font-size: 13px;
}

.kbd {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  background: rgba(255, 255, 255, 0.06);
  padding: 2px 6px;
  border-radius: 4px;
  border: 1px solid var(--border);
  font-size: 11.5px;
}

@media (max-width: 700px) {
  #app { padding: 36px 16px 56px; }
  .live-body { grid-template-columns: 1fr; }
  .card { padding: 16px; }
}

var express = require('express');
var os = require('os');
var router = express.Router();

router.get('/info', function (req, res) {
  res.json({
    name: 'Spck Express',
    expressVersion: require('express/package.json').version,
    nodeVersion: process.version,
    platform: os.platform(),
    arch: os.arch(),
    cpus: os.cpus().length,
    pid: process.pid,
    uptimeSeconds: Math.round(process.uptime()),
    now: new Date().toISOString(),
  });
});

var QUOTES = [
  { text: 'Programs must be written for people to read, and only incidentally for machines to execute.', author: 'Harold Abelson' },
  { text: 'The best way to predict the future is to invent it.',                                          author: 'Alan Kay'        },
  { text: 'Simplicity is prerequisite for reliability.',                                                  author: 'Edsger W. Dijkstra' },
  { text: 'Premature optimization is the root of all evil.',                                              author: 'Donald Knuth'    },
  { text: 'Talk is cheap. Show me the code.',                                                             author: 'Linus Torvalds'  },
  { text: 'First, solve the problem. Then, write the code.',                                              author: 'John Johnson'    },
];

router.get('/quote', function (req, res) {
  var q = QUOTES[Math.floor(Math.random() * QUOTES.length)];
  res.json({ quote: q.text, author: q.author });
});

router.post('/echo', function (req, res) {
  res.json({
    receivedAt: new Date().toISOString(),
    contentType: req.get('content-type') || null,
    youSent: req.body,
  });
});

module.exports = router;

var express = require('express');
var os = require('os');
var router = express.Router();

router.get('/', function (req, res) {
  var mem = process.memoryUsage();
  res.render('index', {
    title: 'Spck Express',
    version: require('express/package.json').version,
    port: req.app.get('port') || process.env.PORT || 9960,
    uptime: process.uptime().toFixed(0) + 's',
    startedAt: new Date(Date.now() - process.uptime() * 1000).toLocaleString(),
    memoryUsed: (mem.heapUsed / 1024 / 1024).toFixed(1),
    nodeVersion: process.version,
    platform: os.platform() + ' ' + os.arch(),
    pid: process.pid,
  });
});

module.exports = router;

var express = require('express');
var router = express.Router();

var USERS = [
  { id: 1, name: 'Ada Lovelace',     role: 'admin'  },
  { id: 2, name: 'Grace Hopper',     role: 'admin'  },
  { id: 3, name: 'Margaret Hamilton', role: 'editor' },
];

router.get('/', function (req, res) {
  res.json({ count: USERS.length, users: USERS });
});

router.get('/:id', function (req, res) {
  var id = Number(req.params.id);
  var user = USERS.find(function (u) { return u.id === id; });
  if (!user) return res.status(404).json({ error: 'Not found', id: id });
  res.json(user);
});

module.exports = router;
